    public void i_create_a_jar_archive_output_stream() throws IOException {
        byteArrayOutputStream = new ByteArrayOutputStream();
        jarArchiveOutputStream = new JarArchiveOutputStream(byteArrayOutputStream);
    }

    @When("I add a first entry named {string}")
    public void i_add_a_first_entry_named(String entryName) throws IOException {
        try {
            JarArchiveEntry entry = new JarArchiveEntry(entryName);
            jarArchiveOutputStream.putArchiveEntry(entry);
            jarArchiveOutputStream.closeArchiveEntry();
        } catch (Exception e) {
            // Handle any exceptions during entry addition
            System.out.println("Exception during first entry addition: " + e.getMessage());
        }
    }

    @When("I add a second entry named {string}")
    public void i_add_a_second_entry_named(String entryName) throws IOException {
        try {
            JarArchiveEntry entry = new JarArchiveEntry(entryName);
            jarArchiveOutputStream.putArchiveEntry(entry);
            jarArchiveOutputStream.closeArchiveEntry();
        } catch (Exception e) {
            // Handle any exceptions during entry addition
            System.out.println("Exception during second entry addition: " + e.getMessage());
