            assertNotNull("ZipFile should not be null", zipFile);
            assertTrue("ZipFile should have entries", zipFile.entries().hasMoreElements());
            zipFile.close();
        } catch (Exception e) {
            fail("Archive should be valid and readable: " + e.getMessage());
        }
    }

