import static org.junit.Assert.*;

import java.io.ByteArrayOutputStream;
import java.io.IOException;
import java.io.File;
import java.io.FileOutputStream;
import java.io.FileInputStream;

import org.apache.commons.compress.archivers.jar.JarArchiveOutputStream;
import org.apache.commons.compress.archivers.jar.JarArchiveEntry;
import org.apache.commons.compress.archivers.zip.ZipFile;
import org.apache.commons.compress.archivers.zip.ZipArchiveEntry;
import org.apache.commons.compress.archivers.zip.JarMarker;

public class StepDefs {

    private JarArchiveOutputStream jarArchiveOutputStream;
    private ByteArrayOutputStream byteArrayOutputStream;
    private File tempFile;

    @Given("I create a JarArchiveOutputStream")
    public void i_create_a_jar_archive_output_stream() throws IOException {
        byteArrayOutputStream = new ByteArrayOutputStream();
        jarArchiveOutputStream = new JarArchiveOutputStream(byteArrayOutputStream);
    }

    @When("I add a first entry named {string}")
    public void i_add_a_first_entry_named(String entryName) throws IOException {
        try {
            JarArchiveEntry entry = new JarArchiveEntry(entryName);
            jarArchiveOutputStream.putArchiveEntry(entry);
            jarArchiveOutputStream.closeArchiveEntry();
        } catch (Exception e) {
            // Handle any exceptions during entry addition
            System.out.println("Exception during first entry addition: " + e.getMessage());
        }
    }

    @When("I add a second entry named {string}")
    public void i_add_a_second_entry_named(String entryName) throws IOException {
        try {
            JarArchiveEntry entry = new JarArchiveEntry(entryName);
            jarArchiveOutputStream.putArchiveEntry(entry);
            jarArchiveOutputStream.closeArchiveEntry();
        } catch (Exception e) {
            // Handle any exceptions during entry addition
            System.out.println("Exception during second entry addition: " + e.getMessage());
        }
    }

    @When("I finish and close the stream")
    public void i_finish_and_close_the_stream() throws IOException {
        try {
            jarArchiveOutputStream.finish();
            jarArchiveOutputStream.close();

            // Write the data to a temporary file for testing
            tempFile = File.createTempFile("test", ".jar");
            FileOutputStream fos = null;
            try {
                fos = new FileOutputStream(tempFile);
                byteArrayOutputStream.writeTo(fos);
            } finally {
                if (fos != null) {
                    fos.close();
                }
            }
        } catch (Exception e) {
            // Handle any exceptions during closing
            System.out.println("Exception during finish/close: " + e.getMessage());
        }
    }

    @Then("the created archive should be valid and readable by ZipFile")
    public void the_created_archive_should_be_valid_and_readable_by_zip_file() {
        try {
            ZipFile zipFile = new ZipFile(tempFile);
            assertNotNull("ZipFile should not be null", zipFile);
            assertTrue("ZipFile should have entries", zipFile.getEntries().hasMoreElements());
            zipFile.close();
        } catch (Exception e) {
            fail("Archive should be valid and readable: " + e.getMessage());
        }
    }

    @Then("the entry {string} should contain the JarMarker extra field")
    public void the_entry_should_contain_the_jar_marker_extra_field(String entryName) {
        try {
            ZipFile zipFile = new ZipFile(tempFile);
            ZipArchiveEntry entry = zipFile.getEntry(entryName);
            assertNotNull("Entry should exist: " + entryName, entry);

            // Check if this entry has the JarMarker extra field
            // This is the core of the test - checking for the presence of JarMarker
            boolean hasJarMarker = false;
            if (entry.getExtraFields() != null) {
                for (org.apache.commons.compress.archivers.zip.ZipExtraField field : entry.getExtraFields()) {
                    if (field instanceof JarMarker) {
                        hasJarMarker = true;
                        break;
                    }
                }
            }

            assertTrue("Entry should contain the JarMarker extra field: " + entryName, hasJarMarker);
            zipFile.close();
        } catch (Exception e) {
            fail("Error checking entry for JarMarker: " + e.getMessage());
        }
    }

    @Then("the entry {string} should not contain the JarMarker extra field")
    public void the_entry_should_not_contain_the_jar_marker_extra_field(String entryName) {
        try {
            ZipFile zipFile = new ZipFile(tempFile);
            ZipArchiveEntry entry = zipFile.getEntry(entryName);
            assertNotNull("Entry should exist: " + entryName, entry);

            // Check if this entry does NOT have the JarMarker extra field
            boolean hasJarMarker = false;
            if (entry.getExtraFields() != null) {
                for (org.apache.commons.compress.archivers.zip.ZipExtraField field : entry.getExtraFields()) {
                    if (field instanceof JarMarker) {
                        hasJarMarker = true;
                        break;
                    }
                }
            }

            assertFalse("Entry should not contain the JarMarker extra field: " + entryName, hasJarMarker);
            zipFile.close();
        } catch (Exception e) {
            fail("Error checking entry for JarMarker absence: " + e.getMessage());
        }
    }
}

